import { defineStore } from 'pinia'

export const useSnackbarStore = defineStore('snackbar', {
  state: () => ({
    snack_message: null,
    snackbar: false,
    timeoutId: null,
  }),
  actions: {
    showMessage(message) {
      this.snack_message = message
      this.snackbar = true

      // Reset previous timeout if exists
      if (this.timeoutId) {
        clearTimeout(this.timeoutId)
      }

      this.timeoutId = setTimeout(() => {
        this.hideMessage()
      }, 4000)
    },
    hideMessage() {
      this.snackbar = false
      this.snack_message = null
    },
  },
  getters: {
    isSnackbarVisible: (state) => state.snackbar,
  },
})
