<template>
  <v-text-field
    class="font-weight-black"
    :model-value="value"
    :type="type"
    :label="label"
    color="#624fc6"
    variant="outlined"
    rounded
    clearable
    :autocomplete="autocomplete"
    lazy-rules
    @update:model-value="$emit('update-value', $event)"
    :hint="hint"
    persistent-hint
    :rules="rules"
    hide-details="auto"
    :min="min"
    :max="max"
  />
</template>
<script setup>
import { defineProps, defineEmits } from "vue";

defineEmits(["update-value"]);
defineProps({
  type: {
    type: [String, Number],
    default: "text",
  },
  min: {
    type: Number,
    required: false,
  },
  max: {
    type: Number,
    required: false,
  },
  label: {
    type: String,
    default: "",
  },
  autocomplete: {
    type: String,
    default: "",
  },
  value: {
    type: [String, Number],
    default: "",
  },
  rules: {
    type: Array,
    default: () => [],
  },
  hint: {
    type: String,
    default: "",
  },
});
</script>
