import { defineStore } from "pinia";
import axios from "axios";
import { useSnackbarStore } from "@/stores/snackbar";
import { server } from "@/config";
export const useSalesDeliveryStore = defineStore("sale_delivery", {
  state: () => ({
    sales_delivery: [],
    barcode_query: "",
    status: null,
    sale_type_delivery: null,
    pageCount: 1,
    params: {
      sortBy: [],
      sortDesc: [],
      page: 1,
      itemsPerPage: 1,
    },
    table_loading: false,
    loading: false,
    retrieve_loading: false,
    loading_info_customer: false,
    change_type_delivery_loading: false,

    date_from: null,
    date_to: null,
  }),

  actions: {
    async reset_table() {
      this.params.page = 1;
      this.params.sortBy = [];
      this.params.sortDesc = [];
      this.barcode_query = "";
      this.pageCount = 1;
      this.table_loading = false;
      this.status = null;
      this.sale_type_delivery = null;
      this.sales_delivery = [];
    },

    async get_sales_delivery() {
      const data = this.params;
      this.table_loading = true;
      try {
        const skip = (data.page - 1) * data.itemsPerPage;
        const limit = data.itemsPerPage;

        let query = "";
        if (this.barcode_query && this.barcode_query.length > 0) {
          query = `&query=${this.barcode_query}`;
        }

        let statusParam = "";
        if (
          this.status &&
          typeof this.status === "object" &&
          this.status.value
        ) {
          statusParam = `&status=${this.status.value}`;
        }
        let saleDeliveryParam = "";
        if (
          this.sale_type_delivery &&
          typeof this.sale_type_delivery === "object" &&
          this.sale_type_delivery.value
        ) {
          saleDeliveryParam = `&sale_type_delivery=${this.sale_type_delivery.value}`;
        }

        var filter_date = "";
        var date_to = null;
        if (this.date_from != null) {
          if (this.date_to == null || this.date_to == undefined) {
            date_to = this.date_from;
          } else if (this.date_to < this.date_from) {
            date_to = this.date_from;
          } else {
            date_to = this.date_to;
          }
          let date = { start_date: this.date_from, end_date: date_to };
          filter_date = "&filter_date=" + JSON.stringify(date);
        }

        const response = await axios.get(
          `${server}/api/get_sales_delivery?skip=${skip}&limit=${limit}${query}${statusParam}${filter_date}${saleDeliveryParam}`
        );

        this.pageCount = response.data.count;
        this.sales_delivery = response.data.result;
        this.table_loading = false;

        return response;
      } catch (error) {
        this.table_loading = false;

        const snackbar = useSnackbarStore();

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "ri:close-circle-fill",
          text: message,
        });

        throw error;
      }
    },


    async change_type_delivery(data) {
      const snackbar = useSnackbarStore();

      this.change_type_delivery_loading = true;
      try {
        const response = await axios.post(`${server}/api/change_type_delivery`, data, {
          headers: {
            "Content-Type": "application/json",
          },
          method: "POST",
        });
        this.change_type_delivery_loading = false;

        snackbar.showMessage({
         color: "deep-purple-accent-4",
          icon: "clarity:success-standard-solid",
          text: response.data.message,
        });

        const updatedSale = response.data.result[0];
        const index = this.sales_delivery.findIndex((e) => e.id === updatedSale.id);
        if (index !== -1) {
          this.sales_delivery.splice(index, 1, updatedSale);
        }

        return response;
      } catch (error) {
        this.change_type_delivery_loading = false;

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "ri:close-circle-fill",
          text: message,
        });

        throw error;
      }
    },
    async retrieve_item(data) {
      const snackbar = useSnackbarStore();

      this.retrieve_loading = true;
      try {
        const response = await axios.post(`${server}/api/retrieve_item`, data, {
          headers: {
            "Content-Type": "application/json",
          },
          method: "POST",
        });
        this.retrieve_loading = false;

        snackbar.showMessage({
         color: "deep-purple-accent-4",
          icon: "clarity:success-standard-solid",
          text: response.data.message,
        });

        const updatedSale = response.data.result[0];
        const index = this.sales_delivery.findIndex((e) => e.id === updatedSale.id);
        if (index !== -1) {
          this.sales_delivery.splice(index, 1, updatedSale);
        }

        return response;
      } catch (error) {
        this.retrieve_loading = false;

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "ri:close-circle-fill",
          text: message,
        });

        throw error;
      }
    },
    async retrieve_all_items(data) {
      const snackbar = useSnackbarStore();

      this.retrieve_loading = true;
      try {
        const response = await axios.post(
          `${server}/api/retrieve_all_items`,
          data,
          {
            headers: {
              "Content-Type": "application/json",
            },
            method: "POST",
          }
        );

        const updatedSale = response.data.result[0];
        const index = this.sales_delivery.findIndex((e) => e.id === updatedSale.id);
        if (index !== -1) {
          this.sales_delivery.splice(index, 1, updatedSale);
        }

        this.retrieve_loading = false;

        snackbar.showMessage({
         color: "deep-purple-accent-4",
          icon: "clarity:success-standard-solid",
          text: response.data.message,
        });

        return response;
      } catch (error) {
        this.retrieve_loading = false;

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "ri:close-circle-fill",
          text: message,
        });

        throw error;
      }
    },
    async add_info_customer(data) {
      const snackbar = useSnackbarStore();

      this.loading_info_customer = true;
      try {
        const response = await axios.post(
          `${server}/api/add_info_customer`,
          data,
          {
            headers: {
              "Content-Type": "application/json",
            },
            method: "POST",
          }
        );

        const updatedSale = response.data.result[0];
        const index = this.sales_delivery.findIndex((e) => e.id === updatedSale.id);
        if (index !== -1) {
          this.sales_delivery.splice(index, 1, updatedSale);
        }

        this.loading_info_customer = false;

        snackbar.showMessage({
          color: "deep-purple-accent-4",
          icon: "clarity:success-standard-solid",
          text: response.data.message,
        });

        return response;
      } catch (error) {
        this.loading_info_customer = false;

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "ri:close-circle-fill",
          text: message,
        });

        throw error;
      }
    },
  },

  getters: {},
});
